 Console.Write("Enter a topic to research: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 var systemPrompt = $"""
     You are a research agent. Your goal is to research the following topic thoroughly: "{topic}"

     You have access to the following tools:
     1. SearchWeb - Search the web for information on a query.
     2. SaveNote - Save an important finding as a note with a category tag.
     3. GetNotes - Retrieve all saved notes to review your findings.

     Instructions:
     - Perform multiple searches to gather diverse information about the topic.
     - Save key findings as notes with appropriate category tags.
     - After gathering enough information (at least 3-5 searches), retrieve your notes
       and produce a comprehensive summary of your research findings.
     - Structure your final summary with sections and bullet points.
     """;

 List<ChatMessage> messages =
 [
