 // --- Tool implementations ---
 sealed class ResearchTools
 {
     private readonly List<(string Category, string Content)> _notes = [];
     private readonly HttpClient _http = new();

     public int NoteCount => _notes.Count;

     [Description("Search the web for information. Returns search result snippets for the given query.")]
     public async Task<string> SearchWeb([Description("The search query")] string query)
     {
         Console.WriteLine($"  [Tool] Searching: \"{query}\"");
         try
         {
             // Use DuckDuckGo instant answer API (no key required)
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
             var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
             var resp = await _http.SendAsync(request);
             var html = await resp.Content.ReadAsStringAsync();

             // Extract text snippets from result blocks
             var snippets = ExtractSnippets(html, maxResults: 5);
             return snippets.Count > 0
                 ? string.Join("\n\n", snippets)
                 : $"No detailed results found for \"{query}\". Try a different query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Save an important research finding as a note.")]
     public string SaveNote(
         [Description("Category tag for the note (e.g., 'definition', 'history', 'statistics')")] string category,
         [Description("The content of the note")] string content)
     {
         _notes.Add((category, content));
         Console.WriteLine($"  [Tool] Note saved [{category}]: {content[..Math.Min(60, content.Length)]}...");
         return $"Note saved under category '{category}'. Total notes: {_notes.Count}";
     }

     [Description("Retrieve all saved research notes to review findings before writing a summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         Console.WriteLine($"  [Tool] Retrieving {_notes.Count} notes");
         var grouped = _notes
             .GroupBy(n => n.Category)
             .Select(g => $"## {g.Key}\n" + string.Join("\n", g.Select(n => $"- {n.Content}")));
         return string.Join("\n\n", grouped);
     }

     private static List<string> ExtractSnippets(string html, int maxResults)
     {
         var snippets = new List<string>();
         // Parse result snippets from DuckDuckGo HTML response
         var marker = "class=\"result__snippet";
         var pos = 0;
         while (snippets.Count < maxResults && (pos = html.IndexOf(marker, pos, StringComparison.Ordinal)) >= 0)
         {
             var start = html.IndexOf('>', pos) + 1;
             var end = html.IndexOf('<', start);
             if (start > 0 && end > start)
             {
                 var text = System.Net.WebUtility.HtmlDecode(html[start..end]).Trim();
                 if (text.Length > 20)
                     snippets.Add(text);
             }
             pos = start;
         }
         return snippets;
     }
 }
